+interface CircuitState {
+  failures: number;
+  state: "closed" | "open" | "half-open";
+  openedAt: number;
+  cooldown: number;
+  halfOpenRequests: number;
+}
+
+export interface CircuitRequest {
+  state: CircuitState;
+  probe: boolean;
+  outcome?: "success" | "failure" | "neutral";
+}
+
+export function resolveCircuitBreaker(
+  option: CircuitBreakerOptions | undefined
+): CircuitBreakerConfig | undefined {
+  if (!option) {
+    return;
+  }
+  if (option === true) {
+    return {
+      threshold: 5,
+      cooldown: 30_000,
+      halfOpenMaxRequests: 1,
+      failureStatusCodes: defaultFailureStatusCodes,
+    };
+  }
+  return {
+    threshold: option.threshold,
+    cooldown: option.cooldown,
+    halfOpenMaxRequests: option.halfOpenMaxRequests ?? 1,
+    failureStatusCodes: option.failureStatusCodes ?? defaultFailureStatusCodes,
+  };
+}
