+  try {
+    if (request instanceof Request) {
+      return new URL(request.url).origin;
+    }
+    return new URL(request instanceof URL ? request.href : request).origin;
+  } catch {
+    // A relative request without a base URL has no portable origin to track.
+  }
+}
