+export class CircuitBreakerStore {
+  private states = new Map<string, CircuitState>();
+
+  acquire(origin: string, config: CircuitBreakerConfig): CircuitRequest {
+    let state = this.states.get(origin);
+    if (!state) {
+      state = {
+        failures: 0,
+        state: "closed",
+        openedAt: 0,
+        cooldown: config.cooldown,
+        halfOpenRequests: 0,
+      };
+      this.states.set(origin, state);
+    }
+
+    if (state.state === "open" && Date.now() - state.openedAt >= state.cooldown) {
+      state.state = "half-open";
+    }
+    if (state.state === "open") {
+      throw new Error("Circuit breaker is open");
+    }
+    if (state.state === "half-open") {
+      if (state.halfOpenRequests >= config.halfOpenMaxRequests) {
